import javax.swing.*;
public class NoAction {
    public static void main(String[] args) {
        JButton btn = new JButton("Save");
        // ActionListener is created but never registered
        java.awt.event.ActionListener listener = e -> System.out.println("saved!");

        JFrame f = new JFrame();
        f.add(btn);
        f.pack();
        f.setVisible(true);
    }
